						Action: plans.NoOp,
					},
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	result := formatter.Format(plan, nil)

	// NoOp changes should not appear in output, no summary shown
	if result != "" {
		t.Fatalf("expected empty result for no-op changes, got: %s", result)
	}
}

