     3→
     4→package format
     5→
     6→import (
     7→	"bytes"
     8→	"fmt"
     9→	"sort"
    10→
    11→	"github.com/hashicorp/terraform/internal/addrs"
    12→	"github.com/hashicorp/terraform/internal/plans"
    13→	"github.com/hashicorp/terraform/internal/schemarepo"
    14→)
    15→
    16→// CompactDiffFormatter formats a plan as a compact, summary-style diff showing
    17→// only resource-level changes without attribute-level detail.
    18→type CompactDiffFormatter struct{}
    19→
    20→// Format renders a plan as a compact summary of resource changes.
    21→// Changes are grouped by action type (Create, Update, Delete, Replace)
    22→// and a summary count is shown at the end.
    23→func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
    24→	if plan == nil || plan.Changes == nil {
    25→		return ""
    26→	}
    27→
    28→	var buf bytes.Buffer
    29→
    30→	// Group changes by action
    31→	creates := []*plans.ResourceInstanceChangeSrc{}
    32→	updates := []*plans.ResourceInstanceChangeSrc{}
    33→	deletes := []*plans.ResourceInstanceChangeSrc{}
    34→	replaces := []*plans.ResourceInstanceChangeSrc{}
    35→	noop := []*plans.ResourceInstanceChangeSrc{}
    36→
    37→	for _, change := range plan.Changes.Resources {
    38→		// Skip deposed objects (only format the current object)
    39→		if change.DeposedKey != "" {
    40→			continue
    41→		}
    42→
    43→		switch change.Action {
    44→		case plans.Create:
    45→			creates = append(creates, change)
    46→		case plans.Update:
    47→			updates = append(updates, change)
    48→		case plans.Delete:
    49→			deletes = append(deletes, change)
    50→		case plans.DeleteThenCreate, plans.CreateThenDelete:
    51→			replaces = append(replaces, change)
    52→		case plans.NoOp:
    53→			noop = append(noop, change)
    54→		default:
    55→			// Handle other actions (Read, Forget, etc.)
    56→			noop = append(noop, change)
    57→		}
    58→	}
    59→
    60→	// Sort each group for consistent output
    61→	sortChanges(creates)
    62→	sortChanges(updates)
    63→	sortChanges(deletes)
    64→	sortChanges(replaces)
    65→
    66→	// Output changes grouped by action type
    67→	if len(creates) > 0 {
    68→		buf.WriteString("# Create
")
    69→		for _, change := range creates {
    70→			buf.WriteString(fmt.Sprintf("  [+] %s
", change.Addr.String()))
    71→		}
    72→	}
    73→
    74→	if len(updates) > 0 {
    75→		buf.WriteString("# Update
")
    76→		for _, change := range updates {
    77→			buf.WriteString(fmt.Sprintf("  [~] %s
", change.Addr.String()))
    78→		}
    79→	}
    80→
    81→	if len(replaces) > 0 {
    82→		buf.WriteString("# Replace
")
    83→		for _, change := range replaces {
    84→			buf.WriteString(fmt.Sprintf("  [-/+] %s
", change.Addr.String()))
    85→		}
    86→	}
    87→
    88→	if len(deletes) > 0 {
    89→		buf.WriteString("# Delete
")
    90→		for _, change := range deletes {
    91→			buf.WriteString(fmt.Sprintf("  [-] %s
", change.Addr.String()))
    92→		}
    93→	}
    94→
    95→	// Summary count
    96→	total := len(creates) + len(updates) + len(replaces) + len(deletes)
    97→	if total > 0 {
    98→		buf.WriteString("
")
    99→		buf.WriteString(fmt.Sprintf("Plan: %d to add, %d to change, %d to destroy.
",
   100→			len(creates), len(updates)+len(replaces), len(deletes)))
   101→	}
   102→
   103→	return buf.String()
   104→}
   105→
   106→// sortChanges sorts changes by their address for consistent output
   107→func sortChanges(changes []*plans.ResourceInstanceChangeSrc) {
   108→	sort.Slice(changes, func(i, j int) bool {
   109→		return changes[i].Addr.String() < changes[j].Addr.String()
   110→	})
   111→}
   112→
   113→// FormatCompactDiff is a convenience function that creates a CompactDiffFormatter
   114→// and formats the given plan.
   115→func FormatCompactDiff(plan *plans.Plan, schemas *schemarepo.Schemas) string {
   116→	formatter := &CompactDiffFormatter{}
   117→	return formatter.Format(plan, schemas)
   118→}
